/** 小游戏叠层 Video 通用参数（wx / qq / qg 等同族 API） */
interface IMiniGameCreateVideoOptions {
    autoplay?: boolean;
    controls?: boolean;
    enableProgressGesture?: boolean;
    height?: number;
    initialTime?: number;
    loop?: boolean;
    muted?: boolean;
    objectFit?: "contain" | "cover" | "fill";
    poster?: string;
    showCenterPlayBtn?: boolean;
    showProgress?: boolean;
    showProgressInControlMode?: boolean;
    src: string;
    underGameView?: boolean;
    width?: number;
    x?: number;
    y?: number;
}

/** 叠层 Video 实例最小能力集 */
interface IMiniGameOverlayVideo {
    destroy?: () => void;
    height?: number;
    offEnded?: (callback: () => void) => void;
    offError?: (callback: (err?: unknown) => void) => void;
    offPause?: (callback: () => void) => void;
    offPlay?: (callback: () => void) => void;
    offWaiting?: (callback: () => void) => void;
    onEnded?: (callback: () => void) => void;
    onError?: (callback: (err?: unknown) => void) => void;
    onPause?: (callback: () => void) => void;
    onPlay?: (callback: () => void) => void;
    onWaiting?: (callback: () => void) => void;
    pause?: () => void;
    play?: () => Promise<void> | void;
    seek?: (timeSec: number) => void;
    src?: string;
    stop?: () => void;
    width?: number;
    x?: number;
    y?: number;
}

/**
 * 微信叠层 Video 桥接类型。
 * @types/wx.d.ts 将 createVideo.src 标为 number，与远端 URL 字符串用法不一致。
 */
interface IWxMinigameOverlayVideoApi {
    createVideo(options: IMiniGameCreateVideoOptions): IMiniGameOverlayVideo;
}

/**
 * 抖音 Video（Mail 用上屏 tt.createVideo；离屏 createOffscreenVideo 仅其它场景）。
 * createVideo 可传 x/y/width/height（物理像素，与 gameCanvas 一致）；Mail 满屏见 OverlayVideoBackendTt。
 */
interface ITtMiniGameVideo extends IMiniGameOverlayVideo {
    offCanplay?: (callback: (scale?: number) => void) => void;
    onCanplay?: (callback: (scale?: number) => void) => void;
    onCandraw?: (callback: (scale?: number) => void) => void;
    paintTo?: (
        canvas: object,
        dx: number,
        dy: number,
        sx: number,
        sy: number,
        sw: number,
        sh: number
    ) => void;
}

declare const tt: {
    createCanvas?: () => HTMLCanvasElement;
    /** 上屏 Video；Mail 满屏叠层见 OverlayVideoBackendTt */
    createVideo?: (options?: IMiniGameCreateVideoOptions) => ITtMiniGameVideo;
    /** 离屏 Video，须 paintTo 或纹理上传后自行展示 */
    createOffscreenVideo?: () => ITtMiniGameVideo;
    getSystemInfoSync?: () => {
        pixelRatio?: number;
        windowHeight: number;
        windowWidth: number;
    };
};

declare const qg: {
    createVideo?: (options: IMiniGameCreateVideoOptions) => IMiniGameOverlayVideo;
    getSystemInfoSync?: () => { windowHeight: number; windowWidth: number };
};

/** 荣耀快游戏 web-adapter 入口，部分 API 与 qg 同族 */
declare const ral: {
    createVideo?: (options: IMiniGameCreateVideoOptions) => IMiniGameOverlayVideo;
    getSystemInfoSync?: () => { windowHeight: number; windowWidth: number };
};

declare const qq: {
    createVideo?: (options: IMiniGameCreateVideoOptions) => IMiniGameOverlayVideo;
    getSystemInfoSync?: () => { windowHeight: number; windowWidth: number };
};

declare const my: {
    createVideo?: (options: IMiniGameCreateVideoOptions) => IMiniGameOverlayVideo;
    createVideoContext?: (id: string) => {
        exitFullScreen?: () => void;
        pause?: () => void;
        play?: () => void;
        requestFullScreen?: (options?: { direction?: number }) => void;
        seek?: (position: number) => void;
        stop?: () => void;
    };
};
